  "inlineSchema": "// Okoumé — Schéma de base de données\n// PostgreSQL via Prisma ORM\n\ngenerator client {\n  provider = \"prisma-client-js\"\n}\n\ndatasource db {\n  provider = \"postgresql\"\n  url      = env(\"DATABASE_URL\")\n}\n\n// ─── UTILISATEURS ─────────────────────────────────────────────────\nmodel User {\n  id           String       @id @default(uuid())\n  phone        String       @unique // +241XXXXXXXXX\n  createdAt    DateTime     @default(now())\n  updatedAt    DateTime     @updatedAt\n  lastSeen     DateTime     @default(now())\n  isActive     Boolean      @default(true)\n  isBanned     Boolean      @default(false)\n  isVerified   Boolean      @default(false) // selfie vérifié\n  subscription Subscription @default(FREE)\n\n  // Profil\n  profile Profile?\n\n  // Relations\n  sentLikes     Like[]    @relation(\"SentLikes\")\n  receivedLikes Like[]    @relation(\"ReceivedLikes\")\n  matchesA      Match[]   @relation(\"MatchUserA\")\n  matchesB      Match[]   @relation(\"MatchUserB\")\n  messages      Message[]\n  reports       Report[]  @relation(\"ReporterUser\")\n  reported      Report[]  @relation(\"ReportedUser\")\n  otps          OTP[]\n  payments      Payment[]\n  blockedBy     Block[]   @relation(\"BlockedUser\")\n  blocking      Block[]   @relation(\"BlockingUser\")\n\n  @@map(\"users\")\n}\n\nenum Subscription {\n  FREE\n  PLUS // Okoumé+ — 5 000 FCFA/mois\n  PREMIUM // Okoumé Premium — 10 000 FCFA/mois (hommes uniquement)\n}\n\n// ─── PROFIL ───────────────────────────────────────────────────────\nmodel Profile {\n  id     String @id @default(uuid())\n  userId String @unique\n  user   User   @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  name        String\n  age         Int\n  gender      Gender\n  province    String\n  city        String\n  bio         String?  @db.VarChar(280)\n  interests   String[] // tableau de centres d'intérêt\n  photos      String[] // URLs des photos (Cloudinary/S3)\n  isIncognito Boolean  @default(false) // Okoumé Premium uniquement\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@map(\"profiles\")\n}\n\nenum Gender {\n  HOMME\n  FEMME\n}\n\n// ─── OTP SMS ──────────────────────────────────────────────────────\nmodel OTP {\n  id        String   @id @default(uuid())\n  userId    String\n  user      User     @relation(fields: [userId], references: [id], onDelete: Cascade)\n  phone     String\n  code      String // Haché avec bcrypt\n  expiresAt DateTime\n  used      Boolean  @default(false)\n  attempts  Int      @default(0)\n  createdAt DateTime @default(now())\n\n  @@map(\"otps\")\n}\n\n// ─── LIKES & MATCHING ─────────────────────────────────────────────\nmodel Like {\n  id         String   @id @default(uuid())\n  fromUserId String\n  toUserId   String\n  isSuper    Boolean  @default(false)\n  createdAt  DateTime @default(now())\n\n  fromUser User @relation(\"SentLikes\", fields: [fromUserId], references: [id], onDelete: Cascade)\n  toUser   User @relation(\"ReceivedLikes\", fields: [toUserId], references: [id], onDelete: Cascade)\n\n  @@unique([fromUserId, toUserId])\n  @@map(\"likes\")\n}\n\nmodel Match {\n  id        String    @id @default(uuid())\n  userAId   String\n  userBId   String\n  createdAt DateTime  @default(now())\n  expiresAt DateTime? // Expire après 7 jours sans message\n\n  userA    User      @relation(\"MatchUserA\", fields: [userAId], references: [id], onDelete: Cascade)\n  userB    User      @relation(\"MatchUserB\", fields: [userBId], references: [id], onDelete: Cascade)\n  messages Message[]\n\n  @@unique([userAId, userBId])\n  @@map(\"matches\")\n}\n\n// ─── MESSAGERIE ───────────────────────────────────────────────────\nmodel Message {\n  id        String      @id @default(uuid())\n  matchId   String\n  senderId  String\n  text      String      @db.VarChar(500)\n  type      MessageType @default(TEXT)\n  readAt    DateTime?\n  createdAt DateTime    @default(now())\n\n  match  Match @relation(fields: [matchId], references: [id], onDelete: Cascade)\n  sender User  @relation(fields: [senderId], references: [id], onDelete: Cascade)\n\n  @@map(\"messages\")\n}\n\nenum MessageType {\n  TEXT\n  IMAGE\n  AUDIO\n}\n\n// ─── PAIEMENTS ────────────────────────────────────────────────────\nmodel Payment {\n  id           String       @id @default(uuid())\n  userId       String\n  user         User         @relation(fields: [userId], references: [id])\n  amount       Int // En FCFA\n  subscription Subscription\n  provider     PayProvider\n  reference    String       @unique // Référence Mobile Money\n  status       PayStatus    @default(PENDING)\n  expiresAt    DateTime // Date de fin d'abonnement\n  createdAt    DateTime     @default(now())\n\n  @@map(\"payments\")\n}\n\nenum PayProvider {\n  AIRTEL_MONEY\n  MOOV_MONEY\n  CARD\n}\n\nenum PayStatus {\n  PENDING\n  SUCCESS\n  FAILED\n  REFUNDED\n}\n\n// ─── SIGNALEMENTS & BLOCAGES ──────────────────────────────────────\nmodel Report {\n  id         String       @id @default(uuid())\n  reporterId String\n  reportedId String\n  reason     ReportReason\n  details    String?\n  status     ReportStatus @default(PENDING)\n  createdAt  DateTime     @default(now())\n\n  reporter User @relation(\"ReporterUser\", fields: [reporterId], references: [id])\n  reported User @relation(\"ReportedUser\", fields: [reportedId], references: [id])\n\n  @@map(\"reports\")\n}\n\nenum ReportReason {\n  FAKE_PROFILE\n  HARASSMENT\n  INAPPROPRIATE_CONTENT\n  SPAM\n  OTHER\n}\n\nenum ReportStatus {\n  PENDING\n  REVIEWED\n  RESOLVED\n  DISMISSED\n}\n\nmodel Block {\n  id        String   @id @default(uuid())\n  blockerId String\n  blockedId String\n  createdAt DateTime @default(now())\n\n  blocker User @relation(\"BlockingUser\", fields: [blockerId], references: [id])\n  blocked User @relation(\"BlockedUser\", fields: [blockedId], references: [id])\n\n  @@unique([blockerId, blockedId])\n  @@map(\"blocks\")\n}\n",
  "inlineSchemaHash": "749eb79f1a80d06ec5f3892d46f77a224e77c8640742761957ef0c1e1f566bf5",
